creating-a-repository-on-github/about-citation-files","actionsOnboardingTip":null},"truncated":false,"viewable":true,"workflowRedirectUrl":null},"copilotInfo":{"documentationUrl":"https://docs.github.com/copilot/overview-of-github-copilot/about-github-copilot-for-individuals","notices":{"codeViewPopover":{"dismissed":false,"dismissPath":"/settings/dismiss-notice/code_view_copilot_popover"}},"userAccess":{"hasSubscriptionEnded":false,"orgHasCFBAccess":false,"userHasCFIAccess":false,"userHasOrgs":false,"userIsOrgAdmin":false,"userIsOrgMember":false,"business":null,"featureRequestInfo":null}},"copilotAccessAllowed":false,"copilotSpacesEnabled":false,"modelsAccessAllowed":false,"modelsRepoIntegrationEnabled":false,"isMarketplaceEnabled":true},"codeViewBlobLayoutRoute.StyledBlob":{"rawLines":["problem 11.1\r","select p.productname,p2.productname  ,\r","count (*)\r","from orderrows o\r","join orderrows o2 on o.orderkey = o2.orderkey\r","and o.productkey \u003e o2.productkey \r","join product p \r","on o.productkey = p.productkey \r","join product p2 \r","on p2.productkey = o2.productkey \r","where o.orderkey \u003e= 10000\r","group by 1,2\r","--problem 11.2\r","with base as (select s.customerkey ,concat(c.givenname , ' ',c.surname )as customer_name ,\r","count(s.orderkey ) as order_number,\r","max(s.orderdate )  last_purchase\r","from sales s\r","join customer c \r","on c.customerkey = s.customerkey \r","where s.orderdate \u003e= '2025-06-01'\r","group by 1 ,2),\r","base2 as(\r","select *\r",",'2026-01-01'::date  - a.last_purchase  as timesince\r","from base a\r","where a.order_number \u003e= 5)\r","select* \r",",case \r","\twhen a2.timesince  \u003e 180 then 'high risk'\r","\twhen a2.timesince \u003e 90 then 'medium risk'\r","\telse 'low risk '\r","end as customer_chrunk\r","from base2 a2\r","--problem 11.3\r","WITH base AS (\r","   SELECT \r","       s.productkey,\r","       s.orderdate,\r","       s.unitprice AS price,\r","       s.quantity,\r","       LAG(s.unitprice) OVER (\r","           PARTITION BY s.productkey \r","           ORDER BY s.orderdate\r","       ) AS prev_price\r","   FROM sales s\r","),\r","price_changes AS (\r","   SELECT \r","       productkey,\r","       orderdate,\r","       price,\r","       prev_price\r","   FROM base\r","   WHERE prev_price IS NOT NULL\r","     AND price \u003c\u003e prev_price\r",")\r","SELECT\r","   pc.productkey,\r","   pc.orderdate AS change_date,\r","   pc.prev_price AS old_price,\r","   pc.price AS new_price,\r","   AVG(\r","       CASE \r","           WHEN s.orderdate \u003e= pc.orderdate - INTERVAL '30 days'\r","            AND s.orderdate \u003c  pc.orderdate\r","           THEN s.quantity\r","       END\r","   ) AS vol_before,\r","   AVG(\r","       CASE \r","           WHEN s.orderdate \u003e= pc.orderdate\r","            AND s.orderdate \u003c= pc.orderdate + INTERVAL '30 days'\r","           THEN s.quantity\r","       END\r","   ) AS vol_after\r","FROM price_changes pc\r","JOIN sales s\r","   ON s.productkey = pc.productkey\r","  AND s.orderdate BETWEEN pc.orderdate - INTERVAL '30 days'\r","                      AND pc.orderdate + INTERVAL '30 days'\r","GROUP BY\r","   pc.productkey,\r","   pc.orderdate,\r","   pc.prev_price,\r","   pc.price;\r","problem 11.4\r","with base as (select s.productkey \r",",sum(s.quantity *s.netprice ) as revenue \r","from sales s\r","group by 1\r","),\r","base2 as (select *\r",",ntile(100) over ( order by a1.revenue desc ) as perc_revenue\r","from base a1),\r","base3 as (select *\r",",case when a2.perc_revenue \u003c= 20 then 'class a'\r","\t  when a2.perc_revenue \u003c= 50 then 'class b'\r","\t  else 'class c'\r","end as invemntory_class\r","from base2 a2),\r","base4 as (\r","select a3.invemntory_class \r",",sum(a3.revenue ) class_revenue\r",",(select sum(s.quantity*s.netprice) from sales s ) as total_revenue\r","from base3 a3\r","group by 1)\r","select *\r",",round((a4.class_revenue /a4.total_revenue *100),2) class_percent\r","from base4 a4\r","--another solution \r","with base as (select s.productkey \r",", sum (s.quantity *s.netprice ) as revenue \r",",(select round(sum(s.quantity*s.netprice ),2) from sales s) as total_revenue\r","from sales s\r","group by 1),\r","base2 as (select * \r",",sum(a1.revenue ) over (order by a1.revenue desc) as runt_revenue\r","from base a1 ),\r","base3 as (select *,round((a2.runt_revenue / a2.total_revenue *100),2) as revenue_percent\r","from base2 a2)\r","select *\r",", case\r","\twhen a3.revenue_percent \u003c= 80 then 'class A'\r","\twhen a3.revenue_percent \u003c= 95 then 'class B'\r","\telse 'class C'\r","end as inventory_class\r","from base3 a3"],"stylingDirectives":null,"colorizedLines":["problem \u003cspan class=\"pl-c1\"\u003e11\u003c/span\u003e.\u003cspan class=\"pl-c1\"\u003e1\u003c/span\u003e","\u003cspan class=\"pl-k\"\u003eselect\u003c/span\u003e \u003cspan class=\"pl-c1\"\u003ep\u003c/span\u003e.\u003cspan class=\"pl-c1\"\u003eproductname\u003c/span\u003e,\u003cspan class=\"pl-c1\"\u003ep2\u003c/span\u003e.\u003cspan class=\"pl-c1\"\u003eproductname\u003c/span\u003e  ,","\u003cspan class=\"pl-c1\"\u003ecount\u003c/span\u003e (\u003cspan class=\"pl-k\"\u003e*\u003c/span\u003e)","\u003cspan class=\"pl-k\"\u003efrom\u003c/span\u003e orderrows o","\u003cspan class=\"pl-k\"\u003ejoin\u003c/span\u003e orderrows o2 \u003cspan class=\"pl-k\"\u003eon\u003c/span\u003e \u003cspan class=\"pl-c1\"\u003eo\u003c/span\u003e.\u003cspan class=\"pl-c1\"\u003eorderkey\u003c/span\u003e \u003cspan class=\"pl-k\"\u003e=\u003c/span\u003e \u003cspan class=\"pl-c1\"\u003eo2\u003c/span\u003e.\u003cspan class=\"pl-c1\"\u003eorderkey\u003c/span\u003e","\u003cspan class=\"pl-k\"\u003eand\u003c/span\u003e \u003cspan class=\"pl-c1\"\u003eo\u003c/span\u003e.\u003cspan class=\"pl-c1\"\u003eproductkey\u003c/span\u003e \u003cspan class=\"pl-k\"\u003e\u0026gt;\u003c/span\u003e \u003cspan class=\"pl-c1\"\u003eo2\u003c/span\u003e.\u003cspan class=\"pl-c1\"\u003eproductkey\u003c/span\u003e ","\u0