s="CodeBlob-module__codeBlobWrapper__RS6In" style="padding-top:8px;padding-bottom:8px"><div id="highlighted-line-menu-positioner" class="position-relative"><div id="copilot-button-positioner" class="position-relative"><div class="CodeBlob-module__codeBlobInner__tfjuQ"><div class="CodeBlob-module__cursorContainer__tiLPm"><div style="height: 2540px;"><div aria-hidden="true" data-testid="navigation-cursor" class="code-navigation-cursor" style="top: 0px; left: 92px;"> </div></div></div><div style="display: contents;"><div style="display: contents;"><textarea id="read-only-cursor-text-area" data-testid="read-only-cursor-text-area" aria-label="file content" aria-readonly="true" inputmode="none" tabindex="0" aria-multiline="true" aria-haspopup="false" data-gramm="false" data-gramm_editor="false" data-enable-grammarly="false" spellcheck="false" autocorrect="off" autocapitalize="off" autocomplete="off" data-ms-editor="false" class="react-blob-textarea react-blob-print-hide" style="resize: none; margin-top: -2px; padding-left: 92px; padding-right: 70px; width: 100%; background-color: unset; box-sizing: border-box; color: transparent; position: absolute; border-width: medium; border-style: none; border-color: currentcolor; border-image: initial; tab-size: 4; outline: none; overflow: auto hidden; height: 2560px; font-size: 12px; line-height: 20px; overflow-wrap: normal; overscroll-behavior-x: none; white-space: pre; z-index: 1;">problem 11.1
select p.productname,p2.productname  ,
count (*)
from orderrows o
join orderrows o2 on o.orderkey = o2.orderkey
and o.productkey &gt; o2.productkey 
join product p 
on o.productkey = p.productkey 
join product p2 
on p2.productkey = o2.productkey 
where o.orderkey &gt;= 10000
group by 1,2
--problem 11.2
with base as (select s.customerkey ,concat(c.givenname , ' ',c.surname )as customer_name ,
count(s.orderkey ) as order_number,
max(s.orderdate )  last_purchase
from sales s
join customer c 
on c.customerkey = s.customerkey 
where s.orderdate &gt;= '2025-06-01'
group by 1 ,2),
base2 as(
select *
,'2026-01-01'::date  - a.last_purchase  as timesince
from base a
where a.order_number &gt;= 5)
select* 
,case 
	when a2.timesince  &gt; 180 then 'high risk'
	when a2.timesince &gt; 90 then 'medium risk'
	else 'low risk '
end as customer_chrunk
from base2 a2
--problem 11.3
WITH base AS (
   SELECT 
       s.productkey,
       s.orderdate,
       s.unitprice AS price,
       s.quantity,
       LAG(s.unitprice) OVER (
           PARTITION BY s.productkey 
           ORDER BY s.orderdate
       ) AS prev_price
   FROM sales s
),
price_changes AS (
   SELECT 
       productkey,
       orderdate,
       price,
       prev_price
   FROM base
   WHERE prev_price IS NOT NULL
     AND price &lt;&gt; prev_price
)
SELECT
   pc.productkey,
   pc.orderdate AS change_date,
   pc.prev_price AS old_price,
   pc.price AS new_price,
   AVG(
       CASE 
           WHEN s.orderdate &gt;= pc.orderdate - INTERVAL '30 days'
            AND s.orderdate &lt;  pc.orderdate
           THEN s.quantity
       END
   ) AS vol_before,
   AVG(
       CASE 
           WHEN s.orderdate &gt;= pc.orderdate
            AND s.orderdate &lt;= pc.orderdate + INTERVAL '30 days'
           THEN s.quantity
       END
   ) AS vol_after
FROM price_changes pc
JOIN sales s
   ON s.productkey = pc.productkey
  AND s.orderdate BETWEEN pc.orderdate - INTERVAL '30 days'
                      AND pc.orderdate + INTERVAL '30 days'
GROUP BY
   pc.productkey,
   pc.orderdate,
   pc.prev_price,
   pc.price;
problem 11.4
with base as (select s.productkey 
,sum(s.quantity *s.netprice ) as revenue 
from sales s
group by 1
),
base2 as (select *
,ntile(100) over ( order by a1.revenue desc ) as perc_revenue
from base a1),
base3 as (select *
,case when a2.perc_revenue &lt;= 20 then 'class a'
	  when a2.perc_revenue &lt;= 50 then 'class b'
	  else 'class c'
end as invemntory_class
from base2 a2),
base4 as (
select a3.invemntory_class 
,sum(a3.revenue ) class_revenue
,(select sum(s.quantity*s.netprice) from sales s ) as total_revenue
from base3 a3
group by 1)
select *
,round((a4.class_revenue /a4.total_revenue *100),2) class_percent
from base4 a4
--another solution 
with base as (select s.productkey 
, sum (s.quantity *s.netprice ) as revenue 
,(select round(sum(s.quantity*s.netprice ),2) from sales s) as total_revenue
from sales s
group by 1),
base2 as (select * 
,sum(a1.revenue ) over (order by a1.revenue desc) as runt_revenue
from base a1 ),
base3 as (select *,round((a2.runt_revenue / a2.total_revenue *100),2) as revenue_percent
from base2 a2)
select *
, case
	when a3.revenue_percent &lt;= 80 then 'class A'
	when a3.revenue_percent &lt;= 95 then 'class B'
	else 'class C'
end as inventory_class
from base3 a3</textarea></div></div><div style="pointer-events: none;"><div class="CodeLines-module__scrollContainerHidden__g7TeZ" tabindex="0"><div class="react-code-file-contents CodeLines-module__codeFileContents__TXelD" data-isolate-layers="true" role="presentation" aria-hidden="true" data-tab-size="4" data-paste-markdown-skip="true" data-hpc="true" containertiming="hpc" style="tab-size: 4; max-width: unset; width: 1062px;"><div class="react-line-numbers-no-virtualization" style="pointer-events: auto; position: relative; z-index: 2;"><div class="react-no-virtualization-wrapper-lines"><div data-line-number="1" class="react-line-number react-code-text" style="padding-right: 16px;">1</div><div data-line-number="2" class="react-line-number react-code-text" style="padding-right: 16px;">2</div><div data-line-number="3" class="react-line-number react-code-text" style="padding-right: 16px;">3</div><div data-line-number="4" class="react-line-number react-code-text" style="padding-right: 16px;">4</div><div data-line-number="5" class="react-line-number react-code-text" style="padding-right: 16px;">5</div><div data-line-number="6" class="react-line-number react-code-text" style="padding-right: 16px;">6</div><div data-line-number="7" class="react-line-number react-code-text" style="padding-right: 16px;">7</div><div data-line-number="8" class="react-line-number react-code-text" style="padding-right: 16px;">8</div><div data-line-number="9" class="react-line-number react-code-text" style="padding-right: 16px;">9</div><div data-line-number="10" class="react-line-number react-code-text" style="padding-right: 16px;">10</div><div data-line-number="11" class="react-line-number react-code-text" style="padding-right: 16px;">11</div><div data-line-number="12" class="react-line-number react-code-text" style="padding-right: 16px;">12</div><div data-line-number="13" class="react-line-number react-code-text" style="padding-right: 16px;">13</div><div data-line-number="14" class="react-line-